// Process AI research results and filter high-value content
const researchData = $input.first().json;
console.log('Processing AI research results:', researchData);

// Parse the AI response
let contentIdeas = [];
try {
  // Extract JSON from AI response
  const text = researchData.text || researchData.content || '';
  const jsonMatch = text.match(/\[\s*\{[\s\S]*\}\s*\]/);

  if (jsonMatch) {
    contentIdeas = JSON.parse(jsonMatch[0]);
  } else {
    // Fallback: try to parse the entire response
    contentIdeas = JSON.parse(text);
  }
} catch (error) {
  console.error('Error parsing AI response:', error);
  // Create fallback content ideas
  contentIdeas = [
    {
      title: 'Tax Deduction Tips for Small Business Owners',
      keywords: ['tax deductions', 'small business', 'israel'],
      contentType: 'blog post',
      targetAudience: 'small business owners',
      wordCount: 1500,
      seoScore: 8,
      businessValue: 9,
      topic: 'tax optimization',
      status: 'New'
    }
  ];
}

// Filter for high-value content (SEO score >= 7 and business value >= 7)
const highValueContent = contentIdeas.filter(idea => 
  (idea.seoScore || 5) >= 7 && (idea.businessValue || 5) >= 7
);

console.log(`Found ${highValueContent.length} high-value content ideas`);

return highValueContent.map(idea => ({
  json: {
    ...idea,
    timestamp: new Date().toISOString(),
    source: 'ai_research',
    priority: 'high'
  }
}));
